const allData = {{workflowparams:allData}};
const id = allData.id;

return {
  id
}

const allData = {{workflowparams:allData}};

const errors = [];
const items = allData.table_putaway_item || [];

for (let index = 0; index < items.length; index++) {
  const item = items[index];

  // Skip cancelled items
  if (item.line_status === 'Cancelled') continue;

  // Skip parent items with split children
  if (item.parent_or_child === 'Parent' && item.is_split === 'Yes') continue;

  const putawayQty = parseFloat(item.putaway_qty) || 0;
  const pendingProcessQty = parseFloat(item.pending_process_qty) || 0;

  // Validate putaway_qty doesn't exceed pending_process_qty
  if (putawayQty > pendingProcessQty) {
    errors.push(
      `Putaway quantity (${putawayQty}) cannot be greater than pending quantity (${pendingProcessQty}) for item ${item.item_code || '#' + (index + 1)}`
    );
  }

  // Validate putaway_qty is not negative
  if (putawayQty < 0) {
    errors.push(
      `Putaway quantity cannot be negative for item ${item.item_code || '#' + (index + 1)}`
    );
  }

  // Check target location for items with putaway_qty > 0 (non-split items only)
  if (item.is_split === 'No' && putawayQty > 0) {
    if (!item.target_location || item.target_location === null || item.target_location === '') {
      errors.push(
        `Target Location is required for item ${item.item_code || '#' + (index + 1)} (Putaway Qty: ${putawayQty})`
      );
    }
  }
}

const isValid = errors.length === 0 ? 1 : 0;

return {
  isValid: isValid,
  errors: errors,
  errorMessage: errors.join('; ')
};

const allData = {{workflowparams:allData}};

const records = [];
const itemsToProcess = []; // Items with putaway_qty > 0 for inventory processing
let totalOriginalQuantity = 0;
let totalPutawayQuantity = 0;
let hasAnyQuantity = false;

for (const item of allData.table_putaway_item) {
  // Skip cancelled items
  if (item.line_status === 'Cancelled') continue;

  // Skip parent items with split children (process children instead)
  if (item.parent_or_child === 'Parent' && item.is_split === 'Yes') continue;

  const putawayQty = parseFloat(item.putaway_qty) || 0;

  // Track totals for parent items only
  if (item.parent_or_child !== 'Child') {
    totalOriginalQuantity += parseFloat(item.qty_to_putaway) || 0;
  }
  totalPutawayQuantity += putawayQty;

  // Only create records for items with quantity
  if (putawayQty > 0) {
    hasAnyQuantity = true;

    // Add to putaway records
    records.push({
      line_index: item.line_index,
      item_code: item.item_code,
      item_name: item.item_name,
      item_desc: item.item_desc || '',
      batch_no: item.batch_no || '',
      source_inv_category: item.source_inv_category,
      target_inv_category: item.target_inv_category,
      store_in_qty: putawayQty,
      item_uom: item.item_uom,
      source_bin: item.source_bin || '',
      target_location: item.target_location || '',
      remark: item.remark || '',
      line_status: 'Confirmed',
      confirmed_by: {{workflowparams:confirmed_by}} || "",
      confirmed_at: new Date().toISOString().replace("T", " ").slice(0, 19),
    });

    // Add to items for inventory processing
    itemsToProcess.push({
      item_code: item.item_code,
      item_uom: item.item_uom,
      putaway_qty: putawayQty,
      source_bin: item.source_bin || '',
      storage_location: item.storage_location || '',
      target_location: item.target_location || '',
      batch_no: item.batch_no || '',
      source_inv_category: item.source_inv_category,
      target_inv_category: item.target_inv_category,
      unit_price: parseFloat(item.unit_price) || 0,
      hu_data: item.hu_data || '',
    });
  }
}

// Extract unique item codes for Item master lookup
const uniqueItemCodes = [...new Set(itemsToProcess.map(i => i.item_code))];

return {
  records,
  itemsToProcess,
  uniqueItemCodes,
  totalOriginalQuantity,
  totalPutawayQuantity,
  hasAnyQuantity
};

const originalPutawayData = {{node:get_node_C64LC1sr.data.data}};
const allData = {{workflowparams:allData}};
const newRecords = {{node:code_node_qfSZO0bi.data.records}};

const originalItems = [...(originalPutawayData.table_putaway_item || [])];
const originalRecords = originalPutawayData.table_putaway_records || [];

const workflowItemMap = {};
for (const item of allData.table_putaway_item) {
  workflowItemMap[String(item.line_index)] = item;
}

// Calculate total putaway quantity per PARENT from new records
const parentPutawayMap = {};
for (const record of newRecords) {
  const lineIndexStr = String(record.line_index);
  const parentLineIndex = lineIndexStr.includes(' - ') 
    ? lineIndexStr.split(' - ')[0] 
    : lineIndexStr;
  const current = parentPutawayMap[parentLineIndex] || 0;
  parentPutawayMap[parentLineIndex] = current + (parseFloat(record.store_in_qty) || 0);
}

// Update each original item (parents only)
const updatedItems = originalItems.map(originalItem => {
  const lineIndexStr = String(originalItem.line_index);
  const totalPutawayQty = parentPutawayMap[lineIndexStr] || 0;
  const currentPending = parseFloat(originalItem.pending_process_qty) || 0;
  const newPendingQty = Math.max(0, currentPending - totalPutawayQty);

  let lineStatus;
  if (originalItem.line_status === 'Cancelled') {
    lineStatus = 'Cancelled';
  } else if (newPendingQty === 0 && totalPutawayQty > 0) {
    lineStatus = 'Completed';
  } else if (totalPutawayQty > 0) {
    lineStatus = 'In Progress';
  } else {
    lineStatus = originalItem.line_status || 'Open';
  }

  return {
    ...originalItem,
    pending_process_qty: newPendingQty,
    line_status: lineStatus,
    putaway_qty: 0,
    target_location: '',
    remark: '',
    is_split: 'No',
    parent_or_child: 'Parent'
  };
});

const combinedRecords = [...originalRecords, ...newRecords];

// Calculate overall to_status
let toStatus;
const allCompleted = updatedItems.every(item => 
  item.line_status === 'Completed' || item.line_status === 'Cancelled'
);
const anyInProgress = updatedItems.some(item => 
  item.line_status === 'In Progress' || item.line_status === 'Completed'
);

if (allCompleted) {
  toStatus = 'Completed';
} else if (anyInProgress) {
  toStatus = 'In Progress';
} else {
  toStatus = 'Open';
}

return { updatedItems, combinedRecords, toStatus };

const allData = {{workflowparams:allData}};
const itemsToProcess = {{node:code_node_qfSZO0bi.data.itemsToProcess}};
const itemMasterData = {{node:search_node_6yzlT81I.data.data}} || [];

// Helper: round to 3 decimal places
const roundQty = (value) => parseFloat(parseFloat(value || 0).toFixed(3));
const roundPrice = (value) => parseFloat(parseFloat(value || 0).toFixed(4));

// Build item master lookup map
const itemMasterMap = {};
for (const item of itemMasterData) {
  itemMasterMap[item.id] = item;
}

// Array to collect inventory movements for loop processing
const inventoryMovements = [];

for (const mat of itemsToProcess) {
  const itemData = itemMasterMap[mat.item_code];

  if (!itemData) {
    continue;
  }

  // UOM conversion
  let basedQty = mat.putaway_qty;
  if (mat.item_uom !== itemData.based_uom && itemData.table_uom_conversion) {
    for (const uom of itemData.table_uom_conversion) {
      if (mat.item_uom === uom.alt_uom_id) {
        basedQty = roundQty(mat.putaway_qty * uom.base_qty);
        break;
      }
    }
  }
  basedQty = roundQty(basedQty);

  const isBatchManaged = itemData.item_batch_management === 1;

  // OUT movement from source_bin
  inventoryMovements.push({
    movement: "OUT",
    item_id: mat.item_code,
    item_uom: mat.item_uom,
    based_uom: itemData.based_uom,
    quantity: mat.putaway_qty,
    based_qty: basedQty,
    bin_location_id: mat.source_bin,
    batch_id: mat.batch_no || null,
    inventory_category: mat.source_inv_category,
    unit_price: roundPrice(mat.unit_price),
    total_price: roundPrice(mat.unit_price * basedQty),
    costing_method_id: itemData.material_costing_method || "",
    is_batch_managed: isBatchManaged ? 1 : 0,
    transaction_type: "TO - PA",
    trx_no: allData.to_id,
    parent_trx_no: allData.receiving_no || "",
    plant_id: allData.plant_id,
    organization_id: allData.organization_id,
  });

  // IN movement to target_location
  inventoryMovements.push({
    movement: "IN",
    item_id: mat.item_code,
    item_uom: mat.item_uom,
    based_uom: itemData.based_uom,
    quantity: mat.putaway_qty,
    based_qty: basedQty,
    storage_location: mat.storage_location,
    bin_location_id: mat.target_location,
    batch_id: mat.batch_no || null,
    inventory_category: mat.target_inv_category,
    unit_price: roundPrice(mat.unit_price),
    total_price: roundPrice(mat.unit_price * basedQty),
    costing_method_id: itemData.material_costing_method || "",
    is_batch_managed: isBatchManaged ? 1 : 0,
    transaction_type: "TO - PA",
    trx_no: allData.to_id,
    parent_trx_no: allData.receiving_no || "",
    plant_id: allData.plant_id,
    organization_id: allData.organization_id,
    hu_data: mat.hu_data || "",
  });
}

return {
  inventoryMovements: inventoryMovements,
  inventoryMovementsLength: inventoryMovements.length
};

const allData = {{workflowparams:allData}};
const currentToStatus = {{node:code_node_KbJLkjP8.data.toStatus}};
const putawaySetup = {{node:get_node_ca2032Ub.data.data}};
const otherPutawayTOs = {{node:search_node_SVMdNd3K.data.data}} || [];
const qiLots = {{node:search_node_T5BGLPpK.data.data}} || [];

const currentToId = String(allData.id);
const grNo = allData.gr_no;

// Check if auto_completed_gr is enabled
const isAutoCompleteGR = putawaySetup && putawaySetup.auto_completed_gr === 1 ? 1 : 0;

// Check if ALL putaway TOs are completed
let allTOsCompleted = 1;

// Current TO status (use the calculated status, not database status)
if (currentToStatus !== 'Completed') {
  allTOsCompleted = 0;
}

// Check other TOs (excluding current one by ID comparison)
for (const to of otherPutawayTOs) {
  // Skip current TO - use String() to ensure consistent comparison
  if (String(to.id) === currentToId) {
    continue;
  }

  // Check if this other TO is not completed
  if (to.to_status !== 'Completed') {
    allTOsCompleted = 0;
    break;
  }
}

// Check if ALL QI lots are completed
let allQICompleted = 1;
if (qiLots.length > 0) {
  for (const qi of qiLots) {
    if (qi.receiving_insp_status !== 'Completed') {
      allQICompleted = 0;
      break;
    }
  }
}

// Determine GR putaway status and gr_status
let grPutawayStatus;
let grStatus = "Received";
let isGRCompleted = 0;

if (allTOsCompleted === 1 && allQICompleted === 1) {
  grPutawayStatus = 'Completed';
  if (isAutoCompleteGR === 1) {
    grStatus = 'Completed';
    isGRCompleted = 1;
  }
} else {
  grPutawayStatus = 'In Progress';
}

return {
  grNo: grNo,
  grPutawayStatus: grPutawayStatus,
  grStatus: grStatus,
  allTOsCompleted: allTOsCompleted,
  allQICompleted: allQICompleted,
  isAutoCompleteGR: isAutoCompleteGR,
  isGRCompleted: isGRCompleted
};

const inventoryMovements = {{node:code_node_M7XzDZ48.data.inventoryMovements}} || [];
const currentIndexRaw = {{node:get_cache_node_CqyAlkUh.data}};
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0;
const data = inventoryMovements[index];
const movement = data.movement;
const huData = data.hu_data && data.hu_data !== "" ? JSON.parse(data.hu_data) : null;

return {
  data,
  movement,
  index,
  nextIndex: index + 1,
  huData,
  huId: huData?.handling_unit_id || "",
}

let huData = {{node:code_node_dofqVRSn.data.huData}} || null;
if (huData && huData?.table_hu_items && huData?.table_hu_items.length > 0) {
  huData.table_hu_items[0].location_id = {{node:code_node_dofqVRSn.data.data.bin_location_id}};
  huData.table_hu_items[0].balance_id = {{node:workflow_node_wCxvhaAr.data.balanceId}} || "";
}

return {
  table_hu_items: huData?.table_hu_items || [],
  hasHuData: huData?.hasHuData || 0,
  handling_unit_id: huData?.handling_unit_id || "",
  handling_no: huData?.handling_no || "",
  hu_material_id: huData?.hu_material_id || "",
  hu_type: huData?.hu_type || "",
  hu_uom: huData?.hu_uom || "",
  remark: huData?.remark || "",
}
